-- SEED: week-1 matchup + pick pools (roster 5 = dachhack/Happy Campers vs roster 1).
insert into matchup (league_id, week, home_roster_id, away_roster_id, status, lock_at)
select (select id from league where sleeper_league_id='1181483840740397056' and season='2026'), 1, 5, 1, 'scheduled', '2026-09-05T00:20:00Z'
on conflict (league_id, week, home_roster_id, away_roster_id) do update set lock_at=excluded.lock_at, status='scheduled';

insert into sleeper_lineup (league_id, week, roster_id, starters_json)
