from (values
  (1, 5, '[{"slug": "cade-stover", "full": "Cade Stover", "pos": "TE"}, {"slug": "jordan-addison", "full": "Jordan Addison", "pos": "WR"}, {"slug": "brock-bowers", "full": "Brock Bowers", "pos": "TE"}, {"slug": "josh-jacobs", "full": "Josh Jacobs", "pos": "RB"}, {"slug": "jalen-milroe", "full": "Jalen Milroe", "pos": "QB"}, {"slug": "alvin-kamara", "full": "Alvin Kamara", "pos": "RB"}, {"slug": "caleb-williams", "full": "Caleb Williams", "pos": "QB"}, {"slug": "michael-mayer", "full": "Michael Mayer", "pos": "TE"}, {"slug": "wandale-robinson", "full": "Wan''Dale Robinson", "pos": "WR"}, {"slug": "joe-mixon", "full": "Joe Mixon", "pos": "RB"}, {"slug": "christian-kirk", "full": "Christian Kirk", "pos": "WR"}, {"slug": "terry-mclaurin", "full": "Terry McLaurin", "pos": "WR"}, {"slug": "travis-etienne", "full": "Travis Etienne", "pos": "RB"}, {"slug": "cole-kmet", "full": "Cole Kmet", "pos": "TE"}, {"slug": "jaylin-noel", "full": "Jaylin Noel", "pos": "WR"}, {"slug": "russell-wilson", "full": "Russell Wilson", "pos": "QB"}, {"slug": "george-kittle", "full": "George Kittle", "pos": "TE"}, {"slug": "cedric-tillman", "full": "Cedric Tillman", "pos": "WR"}, {"slug": "jack-bech", "full": "Jack Bech", "pos": "WR"}, {"slug": "devonta-smith", "full": "DeVonta Smith", "pos": "WR"}, {"slug": "tyrone-tracy", "full": "Tyrone Tracy", "pos": "RB"}, {"slug": "dallas-goedert", "full": "Dallas Goedert", "pos": "TE"}, {"slug": "trevor-lawrence", "full": "Trevor Lawrence", "pos": "QB"}, {"slug": "jaylin-lane", "full": "Jaylin Lane", "pos": "WR"}, {"slug": "christian-mccaffrey", "full": "Christian McCaffrey", "pos": "RB"}, {"slug": "chimere-dike", "full": "Chimere Dike", "pos": "WR"}, {"slug": "george-pickens", "full": "George Pickens", "pos": "WR"}, {"slug": "christian-watson", "full": "Christian Watson", "pos": "WR"}, {"slug": "baker-mayfield", "full": "Baker Mayfield", "pos": "QB"}, {"slug": "davante-adams", "full": "Davante Adams", "pos": "WR"}, {"slug": "jalen-mcmillan", "full": "Jal