  (1, 1, '[{"slug": "kyler-murray", "full": "Kyler Murray", "pos": "QB"}, {"slug": "jayden-daniels", "full": "Jayden Daniels", "pos": "QB"}, {"slug": "darren-waller", "full": "Darren Waller", "pos": "TE"}, {"slug": "marcus-mariota", "full": "Marcus Mariota", "pos": "QB"}, {"slug": "cj-stroud", "full": "C.J. Stroud", "pos": "QB"}, {"slug": "jacoby-brissett", "full": "Jacoby Brissett", "pos": "QB"}, {"slug": "lequint-allen", "full": "LeQuint Allen", "pos": "RB"}, {"slug": "chris-olave", "full": "Chris Olave", "pos": "WR"}, {"slug": "adonai-mitchell", "full": "Adonai Mitchell", "pos": "WR"}, {"slug": "quentin-johnston", "full": "Quentin Johnston", "pos": "WR"}, {"slug": "chase-brown", "full": "Chase Brown", "pos": "RB"}, {"slug": "quinn-ewers", "full": "Quinn Ewers", "pos": "QB"}, {"slug": "xavier-legette", "full": "Xavier Legette", "pos": "WR"}, {"slug": "pat-freiermuth", "full": "Pat Freiermuth", "pos": "TE"}, {"slug": "rhamondre-stevenson", "full": "Rhamondre Stevenson", "pos": "RB"}, {"slug": "tank-bigsby", "full": "Tank Bigsby", "pos": "RB"}, {"slug": "raheim-sanders", "full": "Raheim Sanders", "pos": "RB"}, {"slug": "brian-thomas", "full": "Brian Thomas", "pos": "WR"}, {"slug": "pat-bryant", "full": "Pat Bryant", "pos": "WR"}, {"slug": "konata-mumpfield", "full": "Konata Mumpfield", "pos": "WR"}, {"slug": "arian-smith", "full": "Arian Smith", "pos": "WR"}, {"slug": "anthony-richardson", "full": "Anthony Richardson", "pos": "QB"}, {"slug": "malik-nabers", "full": "Malik Nabers", "pos": "WR"}, {"slug": "bijan-robinson", "full": "Bijan Robinson", "pos": "RB"}, {"slug": "devon-achane", "full": "De''Von Achane", "pos": "RB"}, {"slug": "jaxson-dart", "full": "Jaxson Dart", "pos": "QB"}, {"slug": "puka-nacua", "full": "Puka Nacua", "pos": "WR"}, {"slug": "terrance-ferguson", "full": "Terrance Ferguson", "pos": "TE"}, {"slug": "nico-collins", "full": "Nico Collins", "pos": "WR"}, {"slug": "sam-laporta", "full": "Sam LaPorta", "pos": "TE"}, {"slug": "isiah-pacheco", "full